def send_otp_email(to_email, otp, purpose='login'):
    body = f"""<div style="font-family:Arial;max-width:480px;margin:auto;background:#121212;padding:40px;border-radius:16px;">
      <div style="text-align:center;"><span style="font-size:48px;">🎵</span><h1 style="color:#1db954;">MoodTune</h1></div>
      <div style="background:#282828;border-radius:12px;padding:32px;text-align:center;">
        <p style="color:#fff;">Your OTP:</p>
        <div style="background:#1db954;border-radius:12px;padding:20px;margin:20px 0;">
          <span style="font-size:40px;font-weight:900;letter-spacing:12px;color:#000;">{otp}</span>
        </div>
        <p style="color:#b3b3b3;">Expires in 5 minutes.</p>
      </div></div>"""
    msg = MIMEMultipart('alternative')
    msg['Subject'] = 'MoodTune - Your OTP'
    msg['From'] = MAIL_EMAIL
    msg['To'] = to_email
    msg.attach(MIMEText(body, 'html'))
    try:
        with smtplib.SMTP_SSL('smtp.gmail.com', 465) as s:
            s.login(MAIL_EMAIL, MAIL_PASSWORD)
            s.sendmail(MAIL_EMAIL, to_email, msg.as_string())
        return True
    except Exception as e:
        print(f"Email error: {e}")
        return False

def generate_otp(): return str(random.randint(100000, 999999))

def init_db():
    with sqlite3.connect(DB_PATH) as db:
        db.execute("""CREATE TABLE IF NOT EXISTS users (id INTEGER PRIMARY KEY AUTOINCREMENT,
            username TEXT UNIQUE NOT NULL, email TEXT UNIQUE NOT NULL, password_hash TEXT NOT NULL,
            theme TEXT DEFAULT 'dark', verified INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)""")
        db.execute("""CREATE TABLE IF NOT EXISTS liked_tracks (id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL, track_id INTEGER NOT NULL, track_data TEXT NOT NULL,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id), UNIQUE(user_id, track_id))""")
        db.execute("""CREATE TABLE IF NOT EXISTS listening_history (id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id INTEGER NOT NULL, track_id INTEGER NOT NULL, track_data TEXT NOT NULL,
            played_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id))""")
        try: db.execute('ALTER TABLE users ADD COLUMN verified INTEGER DEFAULT 0')
        except: pass
        db.commit()

init_db()
def hash_password(p): return hashlib.sha256(p.encode()).hexdigest()

