MOOD_KEYWORDS = {
    "happy":["happy","joy","cheerful","glad","upbeat","positive","elated"],
    "sad":["sad","unhappy","depressed","heartbroken","melancholy","lonely","down"],
    "energetic":["energetic","pumped","excited","workout","gym","running","hyped"],
    "chill":["chill","relax","calm","peaceful","study","focus","quiet","work"],
    "angry":["angry","mad","furious","frustrated","rage","aggressive"],
    "romantic":["romantic","love","date","anniversary","intimate","passionate"],
    "party":["party","dance","club","celebrate","fun","groove"],
    "melancholic":["melancholic","nostalgic","bittersweet","wistful","longing"],
    "hopeful":["hopeful","optimistic","motivated","inspired","determined"],
    "peaceful":["peaceful","serene","tranquil","meditate","yoga","sleep"],
}
MOOD_GENRE_AFFINITY = {
    "happy":["pop","disco","reggae","country"],
    "sad":["blues","classical","pop","jazz"],
    "energetic":["metal","hiphop","disco","rock"],
    "chill":["jazz","reggae","classical","blues"],
    "angry":["metal","rock","hiphop"],
    "romantic":["jazz","classical","pop"],
    "party":["disco","hiphop","pop"],
    "melancholic":["blues","jazz","classical","country"],
    "hopeful":["reggae","pop","hiphop","country"],
    "peaceful":["classical","jazz","reggae"],
}

def get_streaming_links(title, artist):
    q = f"{title} {artist}".replace(" ","+")
    return {"spotify":f"https://open.spotify.com/search/{q}","youtube":f"https://www.youtube.com/results?search_query={q}","apple_music":f"https://music.apple.com/search?term={q}","amazon_music":f"https://music.amazon.com/search/{q}"}

def detect_moods(text):
    tl = text.lower()
    detected = [m for m,kws in MOOD_KEYWORDS.items() if any(k in tl for k in kws)]
    return detected if detected else ["happy","chill"]

def recommend_tracks(mood_text, n=12, preferred_genres=[]):
    moods = detect_moods(mood_text)
    preferred_set = set()
    for m in moods: preferred_set.update(MOOD_GENRE_AFFINITY.get(m,[]))
    preferred_set.update([g.lower() for g in preferred_genres])
    scored = [(sum(1 for m in moods if m in t["mood"])+(2 if t["genre"] in preferred_set else 0)+random.uniform(0,0.5),t) for t in MUSIC_DATABASE]
    scored.sort(key=lambda x: x[0], reverse=True)
    return [dict(t) for _,t in scored[:n]]

@app.route("/api/auth/send-otp", methods=["POST","OPTIONS"])
def send_otp():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json(); email,purpose=data.get("email","").strip(),data.get("purpose","login")
    if not email: return jsonify({"error":"Email required"}),400
    if purpose=="login":
        with sqlite3.connect(DB_PATH) as db:
            if not db.execute('SELECT id FROM users WHERE email=?',(email,)).fetchone(): return jsonify({"error":"No account found"}),404
    otp=generate_otp(); OTP_STORE[email]={"otp":otp,"expires_at":time.time()+300}
    print(f"OTP for {email}: {otp}")
    if not send_otp_email(email,otp,purpose): return jsonify({"error":"Failed to send email"}),500
    return jsonify({"message":f"OTP sent to {email}","success":True})

@app.route("/api/auth/verify-otp", methods=["POST","OPTIONS"])
def verify_otp():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json(); email,otp=data.get("email","").strip(),data.get("otp","").strip()
    stored=OTP_STORE.get(email)
    if not stored: return jsonify({"error":"No OTP found. Request a new one."}),400
    if time.time()>stored["expires_at"]: del OTP_STORE[email]; return jsonify({"error":"OTP expired."}),400
    if stored["otp"]!=otp: return jsonify({"error":"Invalid OTP."}),400
    del OTP_STORE[email]
    with sqlite3.connect(DB_PATH) as db:
        db.row_factory=sqlite3.Row; db.execute('UPDATE users SET verified=1 WHERE email=?',(email,)); db.commit()
        user=db.execute('SELECT * FROM users WHERE email=?',(email,)).fetchone()
    if not user: return jsonify({"error":"User not found"}),404
    return jsonify({"token":str(user["id"]),"username":user["username"],"email":user["email"],"theme":user["theme"]})

@app.route("/api/auth/register", methods=["POST","OPTIONS"])
def register():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json(); username,email,password=data.get("username","").strip(),data.get("email","").strip(),data.get("password","")
    if not username or not email or not password: return jsonify({"error":"All fields required"}),400
    with sqlite3.connect(DB_PATH) as db:
        if db.execute('SELECT id FROM users WHERE email=? OR username=?',(email,username)).fetchone(): return jsonify({"error":"Username or email already exists"}),400
        db.execute('INSERT INTO users (username,email,password_hash,verified) VALUES (?,?,?,0)',(username,email,hash_password(password))); db.commit()
    otp=generate_otp(); OTP_STORE[email]={"otp":otp,"expires_at":time.time()+300}
    print(f"Register OTP for {email}: {otp}")
    if not send_otp_email(email,otp,"register"): return jsonify({"error":"Account created but email failed"}),500
    return jsonify({"message":"Account created! Check your email for OTP.","success":True,"email":email})

@app.route("/api/auth/login", methods=["POST","OPTIONS"])
def login():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json(); email,password=data.get("email","").strip(),data.get("password","")
    with sqlite3.connect(DB_PATH) as db:
        db.row_factory=sqlite3.Row
        user=db.execute('SELECT * FROM users WHERE email=? AND password_hash=?',(email,hash_password(password))).fetchone()
    if not user: return jsonify({"error":"Invalid email or password"}),401
    otp=generate_otp(); OTP_STORE[email]={"otp":otp,"expires_at":time.time()+300}
    print(f"Login OTP for {email}: {otp}")
    if not send_otp_email(email,otp,"login"): return jsonify({"error":"Failed to send OTP"}),500
    return jsonify({"message":"OTP sent to your email!","success":True,"email":email})

@app.route("/api/auth/theme", methods=["POST","OPTIONS"])
def update_theme():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json(); token,theme=data.get("token"),data.get("theme","dark")
    if not token: return jsonify({"error":"Unauthorized"}),401
    with sqlite3.connect(DB_PATH) as db: db.execute('UPDATE users SET theme=? WHERE id=?',(theme,token)); db.commit()
    return jsonify({"theme":theme})

@app.route("/api/user/likes", methods=["GET","POST","DELETE","OPTIONS"])
def user_likes():
    if request.method=="OPTIONS": return jsonify({}),200
    token=request.args.get("token") or (request.get_json() or {}).get("token")
    if not token: return jsonify({"error":"Unauthorized"}),401
    if request.method=="GET":
        with sqlite3.connect(DB_PATH) as db:
            db.row_factory=sqlite3.Row
            rows=db.execute('SELECT track_data FROM liked_tracks WHERE user_id=? ORDER BY created_at DESC',(token,)).fetchall()
        return jsonify({"tracks":[json.loads(r["track_data"]) for r in rows]})
    data=request.get_json(); track=data.get("track")
    if request.method=="POST":
        with sqlite3.connect(DB_PATH) as db: db.execute('INSERT OR IGNORE INTO liked_tracks (user_id,track_id,track_data) VALUES (?,?,?)',(token,track["id"],json.dumps(track))); db.commit()
        return jsonify({"success":True})
    with sqlite3.connect(DB_PATH) as db: db.execute('DELETE FROM liked_tracks WHERE user_id=? AND track_id=?',(token,track["id"])); db.commit()
    return jsonify({"success":True})

@app.route("/api/user/history", methods=["GET","POST","OPTIONS"])
def user_history():
    if request.method=="OPTIONS": return jsonify({}),200
    token=request.args.get("token") or (request.get_json() or {}).get("token")
    if not token: return jsonify({"error":"Unauthorized"}),401
    if request.method=="GET":
        with sqlite3.connect(DB_PATH) as db:
            db.row_factory=sqlite3.Row
            rows=db.execute('SELECT track_data FROM listening_history WHERE user_id=? ORDER BY played_at DESC LIMIT 20',(token,)).fetchall()
        return jsonify({"tracks":[json.loads(r["track_data"]) for r in rows]})
    data=request.get_json(); track=data.get("track")
    with sqlite3.connect(DB_PATH) as db: db.execute('INSERT INTO listening_history (user_id,track_id,track_data) VALUES (?,?,?)',(token,track["id"],json.dumps(track))); db.commit()
    return jsonify({"success":True})

@app.route("/api/health")
def health(): return jsonify({"status":"ok","total_tracks":len(MUSIC_DATABASE)})

@app.route("/api/recommend", methods=["POST","OPTIONS"])
def recommend():
    if request.method=="OPTIONS": return jsonify({}),200
    data=request.get_json()
    tracks=recommend_tracks(data.get("mood","happy"),data.get("n",12),data.get("genres",[]))
    for t in tracks: t["streaming"]=get_streaming_links(t["title"],t["artist"])
    return jsonify({"detected_moods":detect_moods(data.get("mood","")),"tracks":tracks,"count":len(tracks)})

@app.route("/api/similar/<int:track_id>")
def similar(track_id):
    track=next((t for t in MUSIC_DATABASE if t["id"]==track_id),None)
    if not track: return jsonify({"tracks":[]})
    same=[dict(t) for t in MUSIC_DATABASE if t["genre"]==track["genre"] and t["id"]!=track_id]
    result=random.sample(same,min(8,len(same)))
    for t in result: t["streaming"]=get_streaming_links(t["title"],t["artist"])
    return jsonify({"tracks":result})

@app.route("/api/search")
def search():
    q=request.args.get("q","").lower()
    if not q: return jsonify({"tracks":[]})
    results=[dict(t) for t in MUSIC_DATABASE if q in t["title"].lower() or q in t["artist"].lower() or q in t["genre"].lower()][:50]
    for t in results: t["streaming"]=get_streaming_links(t["title"],t["artist"])
    return jsonify({"tracks":results,"count":len(results)})

@app.route("/api/genres")
def genres(): return jsonify({"genres":sorted(set(t["genre"] for t in MUSIC_DATABASE))})

@app.route("/api/tracks")
def all_tracks():
    genre=request.args.get("genre")
    page=int(request.args.get("page",1))
    limit=int(request.args.get("limit",50))
    tracks=MUSIC_DATABASE if not genre else [t for t in MUSIC_DATABASE if t["genre"]==genre]
    total=len(tracks); start=(page-1)*limit; paged=tracks[start:start+limit]
    result=[dict(t)|{"streaming":get_streaming_links(t["title"],t["artist"])} for t in paged]
    return jsonify({"tracks":result,"total":total,"page":page,"limit":limit})

@app.route("/api/audio/<genre>/<filename>")
def serve_audio(genre, filename):
    path=os.path.join(AUDIO_DIR,genre,filename)
    if not os.path.exists(path): return jsonify({"error":"Not found"}),404
    return send_file(path,mimetype="audio/wav")

@app.route("/api/audio-url/<genre>")
def get_audio_url(genre):
    files=glob.glob(os.path.join(AUDIO_DIR,genre,"*.wav"))
    if not files: return jsonify({"url":None})
    filename=os.path.basename(random.choice(files))
    return jsonify({"url":f"/api/audio/{genre}/{filename}"})

